<section class="v4-page-shell"><div class="v4-page-head"><h1>Safe Media Cleanup Queue</h1><p>إضافة ملفات غير مستخدمة إلى queue ثم نقلها إلى <code>storage/trash/media</code> بدل الحذف المباشر.</p></div>
<?php if (!empty($flash)): ?><div class="v4-flash v4-flash-<?= e($flash['type'] ?? 'info') ?>"><?= e($flash['message'] ?? '') ?></div><?php endif; ?>
<div class="v4-kpi-strip"><div class="v4-kpi-card"><strong><?= (int)($usage['total_count'] ?? 0) ?></strong><span>الإجمالي</span></div><div class="v4-kpi-card"><strong><?= (int)($usage['unused_count'] ?? 0) ?></strong><span>غير مستخدمة</span></div><div class="v4-kpi-card"><strong><?= count($queue ?? []) ?></strong><span>داخل queue</span></div></div>
<section class="v4-seo-card"><h2>Queue الحالية</h2><?php if (!empty($queue)): ?><div class="v4-table-wrap"><table class="v4-table"><thead><tr><th>المسار</th><th>الحالة</th><th>الإجراءات</th></tr></thead><tbody><?php foreach ($queue as $row): ?><tr><td><code><?= e($row['path'] ?? '') ?></code></td><td><?= e($row['status'] ?? 'queued') ?></td><td><?php if (($row['status'] ?? 'queued') !== 'archived'): ?><form class="v4-inline-form" method="post" action="<?= e(godyar_v4_base_url('/v4/admin/media-cleanup/archive')) ?>"><?= godyar_v4_csrf_field() ?><input type="hidden" name="path" value="<?= e($row['path'] ?? '') ?>"><button type="submit" class="v4-btn-danger">أرشفة آمنة</button></form><form class="v4-inline-form" method="post" action="<?= e(godyar_v4_base_url('/v4/admin/media-cleanup/unqueue')) ?>"><?= godyar_v4_csrf_field() ?><input type="hidden" name="path" value="<?= e($row['path'] ?? '') ?>"><button type="submit" class="v4-btn-ghost">إزالة</button></form><?php else: ?><span class="v4-badge"><?= e($row['trash_path'] ?? '') ?></span><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div><?php else: ?><div class="v4-empty-state"><p>لا توجد عناصر داخل queue.</p></div><?php endif; ?></section>
<div class="v4-media-usage-grid"><?php foreach (($usage['items'] ?? []) as $item): ?><?php if (!empty($item['is_used'])) continue; ?><article class="v4-usage-card is-unused"><div class="v4-usage-card__media"><img src="<?= e($item['url'] ?? '') ?>" alt="<?= e($item['alt_text'] ?? '') ?>"></div><div class="v4-usage-card__body"><strong><?= e($item['alt_text'] ?? basename((string)($item['path'] ?? ''))) ?></strong><code><?= e($item['path'] ?? '') ?></code><?php if (!empty($item['is_queued'])): ?><span class="v4-badge">Queued</span><?php else: ?><form method="post" action="<?= e(godyar_v4_base_url('/v4/admin/media-cleanup/queue')) ?>"><?= godyar_v4_csrf_field() ?><input type="hidden" name="path" value="<?= e($item['path'] ?? '') ?>"><button type="submit">إضافة إلى queue</button></form><?php endif; ?></div></article><?php endforeach; ?></div></section>
